import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication و Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Safety/authentication-and-login-devices.md","filePath":"fa/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"fa/Safety/authentication-and-login-devices.md"};function r(c,e,p,u,m,h){return o(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="authentication-و-login-device-management" tabindex="-1">Authentication و Login Device Management <a class="header-anchor" href="#authentication-و-login-device-management" aria-label="Permalink to &quot;Authentication و Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> و <code>Login Device Management</code> از ImgBed admin panel، public upload entry و WebDAV access محافظت می‌کنند.</p><p>از این صفحه برای تنظیم access credentials، بررسی signed-in devices و revoke کردن sessions قدیمی در صورت نیاز استفاده کنید.</p><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>admin panel را باز کنید و بروید به:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>این page دو بخش اصلی دارد:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-چه-می‌کند" tabindex="-1">Authentication Management چه می‌کند <a class="header-anchor" href="#authentication-management-چه-می‌کند" aria-label="Permalink to &quot;Authentication Management چه می‌کند&quot;">​</a></h2><p>Authentication Management، access credentials را ذخیره می‌کند.</p><p>دو نوع دارد:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication همان upload password است.</p><p>بعد از تنظیم upload password، visitors عادی باید پیش از استفاده از upload page آن را وارد کنند. اگر نمی‌خواهید public upload page برای همه باز باشد، این گزینه مناسب است.</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="تنظیم-upload-password" tabindex="-1">تنظیم Upload Password <a class="header-anchor" href="#تنظیم-upload-password" aria-label="Permalink to &quot;تنظیم Upload Password&quot;">​</a></h3><p>وقتی upload password configured باشد:</p><ul><li>visitors پیش از استفاده از upload page باید password وارد کنند.</li><li>upload فقط پس از پذیرفته شدن password در دسترس است.</li><li>اگر user-side device sessions enabled باشد، ImgBed آن user-side device را record می‌کند.</li></ul><p>تغییر upload password باعث invalid شدن user-side sessions قدیمی می‌شود. visitors باید password جدید را دوباره وارد کنند.</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication از admin username و password استفاده می‌کند.</p><p>این مورد admin panel را محافظت می‌کند. برای production use، همیشه باید آن را configure کنید.</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="تنظیم-admin-credentials" tabindex="-1">تنظیم Admin Credentials <a class="header-anchor" href="#تنظیم-admin-credentials" aria-label="Permalink to &quot;تنظیم Admin Credentials&quot;">​</a></h3><p>وقتی admin username و password configured باشند:</p><ul><li>باز کردن admin panel نیاز به login دارد.</li><li>login موفق یک admin device record ایجاد می‌کند.</li><li>در Login Device Management می‌توانید devices را review، clean up یا force offline کنید.</li></ul><p>تغییر admin username یا password باعث invalid شدن admin sessions قدیمی می‌شود. باید دوباره sign in کنید.</p><h2 id="login-device-management-چه-می‌کند" tabindex="-1">Login Device Management چه می‌کند <a class="header-anchor" href="#login-device-management-چه-می‌کند" aria-label="Permalink to &quot;Login Device Management چه می‌کند&quot;">​</a></h2><p>Login Device Management دستگاه‌هایی را نشان می‌دهد که sign in کرده‌اند.</p><p>به شما کمک می‌کند بررسی کنید:</p><ul><li>کدام devices به admin panel دسترسی داشته‌اند.</li><li>کدام devices به user-side upload page دسترسی داشته‌اند.</li><li>کدام WebDAV clients متصل شده‌اند.</li><li>device session هنوز valid است یا نه.</li><li>آیا devices قدیمی باید force offline شوند یا نه.</li></ul><p>این page سه tab دارد:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>بالای Login Device Management می‌توانید global cookie behavior را configure کنید.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>کنترل می‌کند user-side login چند روز active بماند.</p><p>مثلاً اگر آن را 14 days بگذارید، visitors معمولاً تا 14 روز لازم نیست upload password را دوباره وارد کنند.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>کنترل می‌کند admin login چند روز active بماند.</p><p>مثلاً اگر 14 days تنظیم شود، administrators معمولاً تا 14 روز لازم نیست دوباره sign in کنند.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>وقتی Secure mode enabled باشد، browsers login cookies را فقط از طریق HTTPS ارسال می‌کنند.</p><p>برای production HTTPS sites آن را enable کنید. برای local HTTP testing آن را enable نکنید؛ وگرنه ممکن است رفتار «login succeeded, but refresh logs me out» ببینید.</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab دستگاه‌هایی را نشان می‌دهد که وارد admin panel شده‌اند.</p><p>device records فقط بعد از configure شدن admin credentials و دسترسی به admin panel از طریق login ظاهر می‌شوند.</p><p>هر device card می‌تواند نشان دهد:</p><ul><li>device و browser information</li><li>first login IP</li><li>last active IP</li><li>login time</li><li>last active time</li><li>expiration time</li><li>current status</li></ul><p>اگر device ناآشنا دیدید، از <code>Force Offline</code> برای invalidate کردن آن استفاده کنید.</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code>، login records قدیمی را در tab فعلی به‌صورت bulk حذف می‌کند.</p><p>وقتی شک دارید sessions قدیمی هنوز روی دستگاه‌های دیگر active هستند، از آن استفاده کنید.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> یک device session را invalidate می‌کند.</p><p>پس از force offline شدن device:</p><ul><li>Admin devices باید دوباره sign in کنند.</li><li>User-side devices باید upload password را دوباره وارد کنند.</li><li>WebDAV clients باید دوباره authenticate کنند.</li></ul><p>Expired یا invalid devices را هم می‌توان remove کرد.</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>current device card با <code>Current Device</code> مشخص می‌شود.</p><p>پس از sign out کردن current device:</p><ul><li>current admin session خارج می‌شود.</li><li>current user-side session خارج می‌شود.</li></ul><p>برای ادامه استفاده از آن بخش باید دوباره sign in کنید.</p>',65)])])}const b=t(d,[["render",r]]);export{f as __pageData,b as default};
